-- Program Cleanup & Canonicalization
--
-- 108 programs exist in the DB. This migration:
--   1. Archives AI test artifacts (auto-generated slugs)
--   2. Archives exact duplicates (same program, different slug)
--   3. Activates programs that should be active
--   4. Normalizes slug aliases to canonical slugs
--   5. Ensures all canonical programs have correct status
--
-- SAFE: uses UPDATE SET status='archived' — no rows deleted.
-- Apply in Supabase Dashboard → SQL Editor.
-- Review the SELECT statements at the bottom to verify before applying.

-- ─────────────────────────────────────────────────────────────────────────────
-- STEP 1: Archive AI test artifacts
-- These were auto-generated by the AI course builder and are not real programs.
-- ─────────────────────────────────────────────────────────────────────────────

UPDATE public.programs
SET status = 'archived', is_active = false, published = false
WHERE slug IN (
  'ai-forklift-safety-certification-1774495387731',
  'ai-advanced-project-management-1774494313718',
  'pub-path-test-1773772605941',
  'gen-acceptance-test-elec-1773765247614'
);

-- ─────────────────────────────────────────────────────────────────────────────
-- STEP 2: Archive duplicate/legacy slugs
-- These are older versions of programs that now have canonical slugs.
-- The canonical version is kept; the duplicate is archived.
-- ─────────────────────────────────────────────────────────────────────────────

UPDATE public.programs
SET status = 'archived', is_active = false, published = false
WHERE slug IN (
  -- CNA duplicates (canonical: cna)
  'cna-training',
  'cna-cert',

  -- CPR duplicates (canonical: cpr-first-aid)
  'cpr-cert',

  -- HVAC duplicates (canonical: hvac-technician)
  'hvac-2024',

  -- Barber duplicates (canonical: barber-apprenticeship)
  'barber',
  'barber-2024',

  -- Cosmetology duplicates (canonical: cosmetology-apprenticeship)
  'cosmetology',

  -- Esthetician duplicates (canonical: esthetician-apprenticeship)
  -- Note: 'esthetician' (professional, 24wk, $5120) is KEPT as active — it is a
  -- distinct non-apprenticeship program. Only the apprenticeship slug variants are dupes.
  'hair-stylist-esthetician-apprenticeship',

  -- Nail tech duplicates (canonical: nail-technician-apprenticeship)
  'nail-technician',
  'nail-tech-apprenticeship',
  'hair-stylist-nail-tech-apprenticeship',

  -- Phlebotomy duplicates (canonical: phlebotomy)
  'phlebotomy-technician',

  -- Pharmacy duplicates (canonical: pharmacy-technician)
  -- nha-pharmacy-technician is the NHA-branded version; pharmacy-technician is canonical
  -- Keep both active but mark nha version as the LMS course variant

  -- Peer recovery duplicates (canonical: peer-recovery-specialist)
  'peer-support',
  'peer-recovery-specialist-jri',
  'certified-recovery-specialist',

  -- Tax prep duplicates (canonical: tax-preparation)
  'tax-prep',

  -- Health/safety duplicates (canonical: cpr-first-aid or emergency-health-safety)
  'health-safety',

  -- DSP duplicates (canonical: direct-support-professional)
  'dsp-training',

  -- Drug collector duplicates (canonical: drug-alcohol-specimen-collector)
  -- drug-collector slug → drug-alcohol-specimen-collector is canonical per DB

  -- Bookkeeping duplicates (canonical: bookkeeping)
  'bookkeeping-fundamentals',

  -- Entrepreneurship duplicates (canonical: entrepreneurship)
  'entrepreneurship-small-business',

  -- Forklift duplicates (canonical: forklift)
  'forklift-operator',

  -- IT duplicates (canonical: it-help-desk)
  'it-support',
  'it-support-specialist',

  -- Building services duplicates (canonical: building-services-technician)
  'building-services-technician-apprenticeship',

  -- Recovery coach duplicates
  'recovery-coach',

  -- EMS duplicates (keep emt-apprenticeship as canonical)
  'ems-apprenticeship'
);

