-- ─────────────────────────────────────────────────────────────────────────────
-- STEP 4: Ensure courses table has rows for all canonical programs
-- Links programs → courses so the LMS engine can serve them.
-- Uses INSERT ... ON CONFLICT DO NOTHING to be safe.
-- ─────────────────────────────────────────────────────────────────────────────

INSERT INTO public.courses (id, title, slug, program_id, status, created_at)
SELECT
  gen_random_uuid(),
  p.title,
  p.slug || '-course',
  p.id,
  'published',
  now()
FROM public.programs p
WHERE p.status = 'active'
  AND p.is_active = true
  AND NOT EXISTS (
    SELECT 1 FROM public.courses c WHERE c.program_id = p.id
  )
ON CONFLICT DO NOTHING;

-- ─────────────────────────────────────────────────────────────────────────────
-- STEP 5: Add short_description to programs that are missing it
-- ─────────────────────────────────────────────────────────────────────────────

-- Ensure column exists (safe if already present)
ALTER TABLE public.programs
  ADD COLUMN IF NOT EXISTS short_description text,
  ADD COLUMN IF NOT EXISTS display_order integer DEFAULT 0,
  ADD COLUMN IF NOT EXISTS category text;

-- Set categories for canonical programs
